  'bamboo-tea-organizer-clear-lid': { name: 'Organisateur Thé Bambou à Couvercle Transparent', closure: 'À Charnière', tagline: 'Organisateur bambou à charnière avec couvercle à fenêtre acrylique', intro: 'Un organisateur de sachets de thé en bambou avec couvercle à charnière à fenêtre acrylique transparente — voir le contenu d’un coup d’œil. Configurations 6 ou 9 compartiments, finition naturelle bambou food-safe, parfait pour présentation retail, chambres d’hôtel et bureaux.' },
  'bamboo-tea-organizer-box': { name: 'Boîte Organisateur Sachets de Thé Bambou', closure: 'Couvercle Coulissant', tagline: 'Organisateur bambou à couvercle coulissant et finition food-safe', intro: 'Une boîte bambou élégante à couvercle coulissant pour organiser sachets de thé ou sachets pyramide. Fil propre, finition food-safe et mécanisme coulissant sans quincaillerie qui maintient le contenu frais. Idéale pour cuisines, cafés et coffrets cadeaux.' },
  'black-wooden-tea-organizer': { name: 'Organisateur Sachets de Thé Bois Noir', closure: 'Magnétique', tagline: 'Organisateur moderne noir mat à fermeture magnétique cachée', intro: 'Un organisateur moderne de sachets de thé en noir mat avec fermeture magnétique cachée. Les lignes épurées et la finition premium conviennent aux cuisines contemporaines et au cadeau corporate. Nombre de compartiments configurable de 4 à 12.' },
