  'wood-metal-tea-station': { name: 'Organisateur Station Thé Bois et Métal', closure: 'Couvercle Amovible', tagline: 'Station industrielle multi-niveaux thé et café', intro: 'Un organisateur station thé et café multi-niveaux en bois et métal thermolaqué — esthétique industrielle moderne pour cafés et bureaux modernes. Couvercles amovibles sur les compartiments de stockage, crochets à tasses intégrés et étagères à accessoires le tout dans une unité freestanding.' },
  'rustic-coffee-bar-caddy-set': { name: 'Set Caddy Rustique Coffee Bar avec Poignées Corde', closure: 'Ouverte', tagline: 'Caddies bois finition brûlée avec poignées latérales en jute', intro: 'Une paire de caddies en bois finition brûlée rustique avec poignées latérales en corde de jute et inscription script Coffee Bar peinte blanche à l’avant. Compartiments divisés ouverts — déposer capsules K-cup, sachets de sucre, agitateurs, sachets de thé. Deux tailles empilables par set. Esthétique farmhouse / coffee-shop.' },
  'oak-tea-box-6-compartment-glass-lid': { name: 'Boîte Thé Chêne 6 Compartiments à Couvercle Verre', closure: 'À Charnière', tagline: 'Boîte chêne massif à couvercle verre complet et gravure TEA BOX', intro: 'Une boîte thé en chêne massif à couvercle verre complet à charnière permettant de voir toute la sélection de thé d’un coup d’œil. Six séparateurs amovibles créent la grille standard 6 compartiments ; TEA BOX gravé au laser à l’avant. Prête pour présentation retail premium.' },
  'rustic-2-drawer-tea-storage-box': { name: 'Boîte Rangement Thé Rustique 2 Tiroirs', closure: 'Tiroir', tagline: 'Meuble 2 tiroirs bois brûlé à poignées anneau laiton antique', intro: 'Un meuble rustique 2 tiroirs à finition brûlée pour sachets de thé, capsules, accessoires ou fournitures de bureau. Poignées anneau en laiton antique et fil visible produisent un look workshop vintage. Empreinte empilable adaptée aux bureaux et coins de comptoir.' },
  'bamboo-4-compartment-snack-caddy': { name: 'Caddy Snack et Thé Bambou 4 Compartiments', closure: 'Ouverte', tagline: 'Caddy bambou compact ouvert pour sachets thé et barres snack', intro: 'Un caddy bambou compact à dessus ouvert avec 4 compartiments internes — dimensionné pour sachets de thé, barres granola, sachets snack ou sachets condiment. Finition naturelle bambou propre, food-safe, empilable et assez petit pour tout comptoir ou étagère de placard.' },
