  'black-coffee-bar-3-compartment': { name: 'Caddy Coffee Bar Noir 3 Compartiments', closure: 'Ouverte', tagline: 'Caddy compact noir mat 3 compartiments avec script Coffee Bar', intro: 'Une version compacte 3 compartiments de notre caddy Coffee Bar vaisseau amiral. Dimensionné pour comptoirs domestiques plus petits ou bureaux. Chaque compartiment 3,7 pouces de large — accueille pods café standard, boîtes sachets thé ou petits contenants accessoires.' },
  'bamboo-8-compartment-clear-lid': { name: 'Boîte Thé Bambou 8 Compartiments à Couvercle Transparent', closure: 'À Charnière', tagline: 'Organisateurs thé bambou deux tailles avec couvercle verre complet à charnière', intro: 'Notre format boîte thé le plus populaire, disponible en 2 tailles — corps bambou avec couvercle verre complet à charnière et 8 compartiments internes. Séparateurs amovibles, fermoir avant laiton, finition food-safe. Cheval de trait polyvalent pour marques thé retail et hôtellerie.' },
  'rotating-360-tea-box': { name: 'Boîte Thé Rotative 360° (Lazy Susan)', closure: 'Ouverte', tagline: 'Organisateur thé bois rotatif pour accès 360° à tous les compartiments', intro: 'Un organisateur thé bois rotatif unique avec rotation douce 360° — chaque compartiment est à un quart de tour. Accueille 8 types de sachets de thé dans slots verticaux ; idéal pour café self-service, hôtel breakfast bars et passionnés thé maison. Finition teinte noyer sur pin massif.' },
  'acacia-3-compartment-open-tray': { name: 'Plateau Caddy Ouvert Acacia 3 Compartiments', closure: 'Ouverte', tagline: 'Plateau long ouvert à 3 compartiments et découpes carry latérales', intro: 'Un plateau long ouvert à 3 compartiments profonds et découpes carry latérales — parfait pour sélection sachets thé, service condiments ou mise en place cuisine prep. Acacia massif tonalité miel à finition huilée frottée main. Se lit comme organisateur et pièce de service.' },
