  'walnut-sliding-box': { name: 'Boîte Noyer à Couvercle Coulissant', closure: 'Couvercle Coulissant', tagline: 'Boîte présentation premium noyer couvercle coulissant', intro: 'Une boîte couvercle coulissant de niveau premium en noyer américain massif — pour produits qui méritent une surface de présentation aussi bonne que le produit lui-même. Le fil chocolat foncé double la valeur perçue.' },
  'sliding-storage-box': { name: 'Boîte Rangement Coulissante (Pin Teinté)', closure: 'Couvercle Coulissant', tagline: 'Boîte coulissante pin teinté à proportions généreuses', intro: 'Une boîte couvercle coulissant pin teinté format plus grand à proportions généreuses — dimensionnée pour sets bijoux, perles mala ou rangement accessoire tabletop. La finition teintée élève le pin vers une esthétique plus premium.' },
