  'pine-adventure-engraved-sliding-box': { name: 'Boîte Coulissante Pin Gravée Our Next Adventure', closure: 'Couvercle Coulissant', tagline: 'Boîte couvercle coulissant fine avec cœur découpé pour gardeurs souvenirs', intro: 'Une boîte pin fine couvercle coulissant gravée Our Next Adventure avec un cœur découpé dans le couvercle — conçue pour couples pour sauver tickets, photos et souvenirs voyage. Un cadeau format long construit autour de moments partagés.' },
  'pine-perfect-match-wedding-box': { name: 'Boîte Coulissante Mariage Pin Perfect Match', closure: 'Couvercle Coulissant', tagline: 'Boîte allumettes personnalisée pour cadeaux mariage', intro: 'Une boîte cadeau mariage personnalisée Perfect Match — une boîte allumettes pin couvercle coulissant imprimée avec les noms du couple et la date, contenant des allumettes longues pour allumage cérémonial bougies. Romantique et pratique.' },
  'bamboo-sliding-storage-set': { name: 'Set Rangement Bambou à Couvercle Coulissant', closure: 'Couvercle Coulissant', tagline: 'Boîtes coulissantes bambou multi-tailles — vendues comme set imbriqué', intro: 'Un set imbriqué de boîtes rangement bambou couvercle coulissant en tailles graduées — parfait pour organisation maison, merchandising retail ou comme set débutant polyvalent pour artisans perles, herbalistes ou passionnés.' },
  'walnut-acrylic-top-trinket-box': { name: 'Boîte Bibelots Noyer à Dessus Acrylique', closure: 'Couvercle Coulissant', tagline: 'Boîte noyer à couvercle acrylique coulissant pour exposition bibelots', intro: 'Une boîte bibelots noyer avec couvercle acrylique clair coulissant — montrer bijoux, pièces monnaie ou petits collectibles en les gardant sans poussière. La combinaison noyer et acrylique propre se sent à la fois chaude et moderne.' },
  'pine-groomsman-cigar-sliding-box': { name: 'Boîte Coulissante Cigare Pin Témoin', closure: 'Couvercle Coulissant', tagline: 'Boîte cigares personnalisée pour cadeaux témoins', intro: 'Une boîte cigares pin longue et fine couvercle coulissant gravée avec monogrammes témoins — dimensionnée pour 4–6 cigares. Vendue en sets 4 pièces pour groupes mariage ; tarification volume pour planificateurs mariage et détaillants cadeau.' },
